var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，他是必不可少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼とともにいることを。","ENG":"that you'll be with him, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和他一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called him to your office. He said he'd be here soon.","TWN":"做好心裡準備後，你將他傳喚到老闆辦公室，得到回應說他馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"관리국 시절에는...... 지휘관이 될 생각이 없냐는 말도 많이 들었습니다.","JPN":"管理局時代には……指揮官になる気はないかとよく聞かれたものです。","ENG":"Back when I was in the Administration, people kept asking me to take the post of commander.","TWN":"在管理局時代……我也多次被問到是否有當指揮官的想法。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"그때는 아직 현장에서 배워야 할 게 많다는 이유로 사양했지만요.","JPN":"あの頃は、まだ現場で学ぶべきことが多いからと遠慮したのですけどね。","ENG":"I declined, saying there was still a lot to learn in the field.","TWN":"那時，我說自己還有很多要在現場學的東西，全都推辭掉了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"사실, 제가 펜릴 전대에 남았던 이유는 세상을 지키고 싶어서였습니다.","JPN":"実のところ、僕がフェンリル戦隊に残ったのは、世界を守りたかったからです。","ENG":"But the real reason I chose to stay in the Fenrir Division was that I wanted to protect the world.","TWN":"但其實，我留在芬里爾戰隊是為了守護世界。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"관리국에 이견은 없었지만...... 위로 올라가면 올라갈수록, 제 바람과는 다른 일을 해야 될 수도 있다고 생각했죠.","JPN":"管理局に異論があるわけではありませんでしたが……地位が上がっていくほど、僕の望みとは異なる仕事をすることになるかもしれないと思ったんです。","ENG":"It wasn't like I had any disagreement with the Administration, but it was clear I'd have to do things I didn't want to do, the higher I up I went.","TWN":"雖然我對管理局沒有什麼意見…… 但越往上爬，我就越覺得該去做那些與我期望相左的事情。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"그런데 설마 관리자님께서 직접 찾아 주실 줄은 몰랐네요.","JPN":"それが、まさか管理者さんが直接訪ねてくるとは思ってもいませんでした。","ENG":"I never expected that you would come for me in person, Administrator.","TWN":"然而，沒想到管理者大人會親自來找我。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"알고 있습니다. 겉으로는 느긋하게 계셔도 사실은 누구보다 모두를 위해 애써 주시는 분이라는 걸요.","JPN":"わかっています。のんびりしているように見えて、本当はみんなのために誰よりも力を尽くしてくれているということを。","ENG":"I know you look care-free, but you struggle to protect everyone.","TWN":"我是知道的。您表面上看起來雖然很散漫，但為了大家卻比任何人都要努力。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"저를 다시 필요로 하시는 이유도 분명 직원들과...... 더 많은 사람들을 지키시기 위해서겠죠.","JPN":"僕をまた必要とされているのも、きっと社員達と……より大勢の人々を守るためなんでしょうね。","ENG":"It's obvious that you need me to protect your employees, and by extension, people in general.","TWN":"您再次需要我的理由，肯定是為了守護員工……和更多的人們吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"괜찮습니다. 펜릴 전대는 어떤 곤경이든 선두에 서서 돌파했으니까요.","JPN":"望むところです。フェンリル戦隊はいかなる苦境においても先頭に立ち、敵陣を突破してきたのですから。","ENG":"It's okay. You know how we were at the Fenrir Division. We were always in the vanguard when trouble came.","TWN":"沒問題的。無論是怎麼樣的困境，芬里爾戰隊都會站在最前線突破它的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"수연이는 늘 너무 멀찍이 앞서가서 문제였지만...... 저는 제 나름대로의 방식으로 도와드리겠습니다.","JPN":"キズナの独断専行にはいつも困らされてましたけど……僕は僕なりのやり方でお手伝いします。","ENG":"Although in Sooyeon's case, being too far ahead of all the others was the problem... Anyway, I'll be of help as much as I can, in a way only I can.","TWN":"雖然秀妍老是太衝前面是個問題……但我會用我的方式幫助您的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"하하, 그래도 오늘 이후로는 더 많이 바빠지시겠네요.","JPN":"ははっ、それにしても、今日からはもっと忙しくなりそうですね。","ENG":"Hah hah, I guess life will be busy for me, starting from today.","TWN":"哈哈，不過今天之後，您應該會變得更忙吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"이래봬도 전 꽤 호기심이 많은 학생이거든요.","JPN":"こう見えても僕、それなりに好奇心旺盛な学生なんですよ。","ENG":"I may not look it, but I'm actually a very curious student.","TWN":"別看我這樣，我好歹也是個好奇心強烈的學生啊。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};